module asyn_fifo #(
    parameter DEPTH = 16,
    parameter WIDTH = 8,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output wire				wfull,
    output wire				rempty,
    output wire [WIDTH-1:0]	rdata
);

reg [ADDR_WIDTH-1:0] wr_ptr_sync1, wr_ptr_sync2;
reg [ADDR_WIDTH-1:0] rd_ptr_sync1, rd_ptr_sync2;

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wr_ptr_sync1 <= 0;
        wr_ptr_sync2 <= 0;
    end else begin
        wr_ptr_sync1 <= wr_ptr_sync2;
        wr_ptr_sync2 <= wr_ptr_sync1 + winc;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rd_ptr_sync1 <= 0;
        rd_ptr_sync2 <= 0;
    end else begin
        rd_ptr_sync1 <= rd_ptr_sync2;
        rd_ptr_sync2 <= rd_ptr_sync1 + rinc;
    end
end

reg [WIDTH-1:0] ram [DEPTH-1:0];

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        ram[0] <= 0;
    end else begin
        ram[wr_ptr_sync2] <= wdata;
    end
end

assign rdata = ram[rd_ptr_sync2];
assign rempty = (wr_ptr_sync2 == rd_ptr_sync2);
assign wfull = ((wr_ptr_sync2 - rd_ptr_sync2) == DEPTH);

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule
